def seq_ratio(a,b):
    return SequenceMatcher(None,a,b).ratio()

def token_f1(a,b):
    atoks = a.split()
    btoks = b.split()
    common = set(atoks) & set(btoks)
    prec = len(common)/len(atoks) if atoks else 0
    rec = len(common)/len(btoks) if btoks else 0
    if prec+rec==0:
        return 0.0
    return 2*prec*rec/(prec+rec)

