    # For LCS normalized length over max length
    def lcs_len(a,b):
        # DP
        la, lb = len(a), len(b)
        dp = [[0]*(lb+1) for _ in range(la+1)]
        for i in range(la-1,-1,-1):
            for j in range(lb-1,-1,-1):
                if a[i]==b[j]:
                    dp[i][j]=1+dp[i+1][j+1]
                else:
                    dp[i][j]=max(dp[i+1][j], dp[i][j+1])
        return dp[0][0]
